/**
 * Função para remover aspas simples e duplas de strings.
 */
function sanitize(value) {
  if (value == null) return '';
  if (typeof value !== 'string') return value;
  // remove ' e "
  return value
            .replaceAll(/['"\/\\]/g, '').trim();
}

