  // Campos gerais
  body.message       = sanitize(body.message);
  body.utm_term      = sanitize(body.utm_term);
  body.utm_medium    = sanitize(body.utm_medium);
  body.utm_source    = sanitize(body.utm_source);
  body.utm_campaign  = sanitize(body.utm_campaign);
  body.utm_content   = sanitize(body.utm_content);
  body.lead.utm_term      = sanitize(body.lead.utm_term);
  body.lead.utm_medium    = sanitize(body.lead.utm_medium);
  body.lead.utm_source    = sanitize(body.lead.utm_source);
  body.lead.utm_campaign  = sanitize(body.lead.utm_campaign);
  body.lead.utm_content   = sanitize(body.lead.utm_content);

  // Campos dentro de lead
  if (body.lead) {
    body.lead.name = sanitize(body.lead.name);
    // Se tiver utm dentro de visit.params
    if (body.lead.visit && body.lead.visit.params) {
      const p = body.lead.visit.params;
      ['gclid','utm_term','utm_medium','utm_source','utm_campaign','utm_content','gad_source'].forEach(k => {
        if (p[k] != null) p[k] = sanitize(p[k]);
      });
    }
  }

  // Reatribui o body limpo ao item
  item.json.body = body;
  return item;
});

